def generate_cluster_config(
    cluster_name: str,
    node_count: int,
    gpus_per_node: int,
    gpu_model: str = "A100-80GB"
) -> dict:
    return {
        "cluster": {
            "name": cluster_name,
            "total_gpus": node_count * gpus_per_node,
            "nodes": [
                {
                    "hostname": f"node-{i:03d}",
                    "gpus": gpus_per_node,
                    "gpu_model": gpu_model,
                }
                for i in range(1, node_count + 1)
            ],
        }
    }

def build_ssh_config(hosts: list[dict]) -> str:
    blocks = []
    for host in hosts:
        lines = [
            f"Host {host['name']}",
            f"    HostName {host['hostname']}",
            f"    User {host['user']}",
        ]
        if host.get("identity_file"):
            lines.append(f"    IdentityFile {host['identity_file']}")
        if host.get("proxy_jump"):
            lines.append(f"    ProxyJump {host['proxy_jump']}")
        blocks.append("\n".join(lines))
    return "\n\n".join(blocks)

def build_gitignore(
    extensions: list[str],
    directories: list[str],
    files: list[str],
    project_name: str = "HPC Project"
) -> str:
    lines = [f"# .gitignore for {project_name}", ""]

    if extensions:
        lines.append("# File extensions")
        for ext in extensions:
            ext = ext if ext.startswith(".") else f".{ext}"
            lines.append(f"*{ext}")
        lines.append("")

    if directories:
        lines.append("# Directories")
        for d in directories:
            d = d if d.endswith("/") else f"{d}/"
            lines.append(d)
        lines.append("")

    if files:
        lines.append("# Specific files")
        for f in files:
            lines.append(f)
        lines.append("")

    return "\n".join(lines)

def parse_git_log(log_output: str, keyword: str = None) -> list[dict]:
    if not log_output.strip():
        return []
    commits = []
    for line in log_output.strip().split("\n"):
        line = line.strip()
        if not line:
            continue
        parts = line.split(" ", 1)
        if len(parts) < 2:
            continue
        commit = {"hash": parts[0], "message": parts[1]}
        if keyword is None or keyword.lower() in commit["message"].lower():
            commits.append(commit)
    return commits

import re

def parse_training_log(log_text: str) -> list[dict]:
    pattern = r'Epoch (\d+)/(\d+) - loss: ([\d.]+) - accuracy: ([\d.]+) - lr: ([\d.]+)'
    results = []
    for match in re.finditer(pattern, log_text):
        results.append({
            "epoch": int(match.group(1)),
            "total_epochs": int(match.group(2)),
            "loss": float(match.group(3)),
            "accuracy": float(match.group(4)),
            "lr": float(match.group(5)),
        })
    return results

from datetime import datetime, timedelta

def plan_cleanup(
    files: list[dict],
    max_age_days: int = 30,
    now: datetime = None
) -> dict:
    if now is None:
        now = datetime.now()
    cutoff = now - timedelta(days=max_age_days)

    to_delete = []
    to_keep = []
    space_freed = 0.0
    space_kept = 0.0

    for f in files:
        if f["last_modified"] < cutoff:
            to_delete.append(f["path"])
            space_freed += f["size_mb"]
        else:
            to_keep.append(f["path"])
            space_kept += f["size_mb"]

    return {
        "to_delete": to_delete,
        "to_keep": to_keep,
        "space_freed_mb": space_freed,
        "space_kept_mb": space_kept,
    }
